select,
member.mobile,
member.user_name
from after_sale
left join member on member.id = after_sale.member_id


    and after_sale.member_id = #{param.memberId}


    and member.mobile = #{param.mobile}


    and member.user_name = #{param.userName}


    and after_sale.store_id = #{param.storeId}


    and after_sale.order_code = #{param.orderCode}


    and after_sale.after_sale_code = #{param.afterSaleCode}


    and after_sale.order_after_status = #{param.orderAfterStatus}


    and after_sale.order_after_type = #{param.orderAfterType}


